// Coleta os dados do nó $('Switch')
const chamados = $('MergePendente').all();

// Função para determinar a saudação com base no horário atual
function obterSaudacao() {
  const hora = new Date().getHours();
  if (hora >= 6 && hora < 12) {
    return "Bom dia";
  } else if (hora >= 12 && hora < 18) {
    return "Boa tarde";
  } else {
    return "Boa noite";
  }
}

// Verifica se há dados e monta a mensagem
if (chamados && chamados.length > 0 && chamados[0].json) {
  const chamado = chamados[0].json; // Pega o primeiro item no formato correto
  const saudacao = obterSaudacao(); // Obtém a saudação adequada

  // Cria a mensagem com os dados do chamado
  const mensagem = `${saudacao}, ${chamado.NOME.split(" ")[0]}.\n\n` +
    `Seu chamado de número ${chamado.ID}, com o título "${chamado.TITULO}", está atualmente com o status "${chamado.STATUS}".\n\n` +
    `Para mais detalhes, acesse o chamado no GLPI: ${chamado.URL}\n\n` +
    `Atenciosamente,\nTecnologia da Informação.`;

  // Retorna a mensagem formatada como string JSON
  return {
    textMessage: {
      msg: JSON.stringify(mensagem.trim())
    }
  };
} else {
  // Retorna uma mensagem padrão caso não haja dados
  return {
    textMessage: {
      msg: JSON.stringify("Não foram encontrados dados do chamado para informar o solicitante.")
    }
  };
}

